import{_ as t,a as e,b as i,c as l,d,e as o,f as r,g as s}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as p,o as n,c as h,a2 as c}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"연합 분산 인덱스","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Other/federated-distributed-index.md","filePath":"ko-KR/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),b={name:"ko-KR/Other/federated-distributed-index.md"};function u(m,a,_,g,x,f){return n(),h("div",null,[...a[0]||(a[0]=[c('<h1 id="연합-분산-인덱스" tabindex="-1">연합 분산 인덱스 <a class="header-anchor" href="#연합-분산-인덱스" aria-label="Permalink to &quot;연합 분산 인덱스&quot;">​</a></h1><p>연합 분산 인덱스는 여러 ImgBed 사이트가 서로 파일 목록을 공유할 수 있게 해 주는 기능입니다.</p><p>쉽게 말하면 다음과 같습니다.</p><ul><li>내 사이트의 일부 폴더를 다른 사람에게 공유할 수 있습니다.</li><li>다른 사람의 노드에 참여해 상대가 공유한 파일 목록을 내 관리자 화면에서 볼 수 있습니다.</li><li>연합 파일은 탐색, 검색, 미리보기, 링크 복사용입니다. 내 저장소에 다시 업로드되는 것은 아닙니다.</li></ul><h2 id="설정-위치" tabindex="-1">설정 위치 <a class="header-anchor" href="#설정-위치" aria-label="Permalink to &quot;설정 위치&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>시스템 설정 -&gt; 기타 설정 -&gt; 연합 분산 인덱스</span></span></code></pre></div><p><img src="'+t+`" alt="로컬 노드" loading="lazy"></p><p>화면은 세 개의 탭으로 구성됩니다.</p><table tabindex="0"><thead><tr><th>탭</th><th>용도</th></tr></thead><tbody><tr><td>로컬 노드</td><td>내 노드 사용 여부, 외부 도메인, 공유 폴더, 송신 인덱스 관리</td></tr><tr><td>내가 참여한 노드</td><td>내가 구독한 다른 ImgBed 노드 관리</td></tr><tr><td>내 노드 참여 신청</td><td>다른 사람이 내 노드에 참여하려는 신청 관리</td></tr></tbody></table><h2 id="처음-설정하기" tabindex="-1">처음 설정하기 <a class="header-anchor" href="#처음-설정하기" aria-label="Permalink to &quot;처음 설정하기&quot;">​</a></h2><ol><li><code>로컬 노드</code>를 엽니다.</li><li><code>사용</code> 스위치를 켭니다.</li><li><code>동기화 폴더</code>에서 공유할 폴더를 선택합니다.</li><li><code>송신 인덱스 업데이트</code>를 누릅니다.</li><li>도메인 변경 확인이 표시되면 현재 도메인이 실제 서비스 도메인인지 확인하고 계속합니다.</li></ol><p>동기화 폴더는 여러 개 선택할 수 있습니다. 비워 두면 전체 폴더를 공유하는 의미입니다.</p><h2 id="로컬-노드" tabindex="-1">로컬 노드 <a class="header-anchor" href="#로컬-노드" aria-label="Permalink to &quot;로컬 노드&quot;">​</a></h2><h3 id="외부-도메인" tabindex="-1">외부 도메인 <a class="header-anchor" href="#외부-도메인" aria-label="Permalink to &quot;외부 도메인&quot;">​</a></h3><p>외부 도메인은 다른 노드가 내 사이트에 접근할 때 사용하는 주소입니다.</p><p>시스템이 자동으로 감지하므로 보통 직접 입력할 필요는 없습니다. 처음 인덱스를 업데이트하거나 도메인이 바뀐 경우 확인 메시지가 표시됩니다.</p><h3 id="동기화-폴더" tabindex="-1">동기화 폴더 <a class="header-anchor" href="#동기화-폴더" aria-label="Permalink to &quot;동기화 폴더&quot;">​</a></h3><p>동기화 폴더는 어떤 파일을 연합 노드에 공유할지 결정합니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>이렇게 설정하면 상대 노드는 이 두 디렉터리 안의 파일만 볼 수 있습니다.</p><h3 id="송신-인덱스-업데이트" tabindex="-1">송신 인덱스 업데이트 <a class="header-anchor" href="#송신-인덱스-업데이트" aria-label="Permalink to &quot;송신 인덱스 업데이트&quot;">​</a></h3><p>다른 노드가 내 사이트에서 동기화할 수 있는 파일 목록을 갱신합니다.</p><p>다음 상황에서 사용합니다.</p><ul><li>연합 기능을 처음 켤 때.</li><li>공유할 파일을 새로 업로드했을 때.</li><li>동기화 폴더를 변경했을 때.</li><li>외부 도메인이 바뀌어 다시 확인해야 할 때.</li></ul><h2 id="다른-노드에-참여하기" tabindex="-1">다른 노드에 참여하기 <a class="header-anchor" href="#다른-노드에-참여하기" aria-label="Permalink to &quot;다른 노드에 참여하기&quot;">​</a></h2><p><code>내가 참여한 노드</code>는 다른 ImgBed 노드를 구독하는 곳입니다.</p><p><img src="`+e+'" alt="내가 참여한 노드" loading="lazy"></p><ol><li>상대에게 초대 링크를 받습니다.</li><li>입력창에 붙여 넣습니다.</li><li><code>참여 신청</code>을 누릅니다.</li><li>상대가 관리자 화면에서 승인할 때까지 기다립니다.</li></ol><p>승인 후에는 <code>수신 인덱스 업데이트</code>를 눌러 상대가 공유한 파일 목록을 동기화합니다.</p><p>특정 노드만 갱신하고 싶다면 해당 노드 카드에서 <code>인덱스 업데이트</code>를 누르면 됩니다.</p><p><img src="'+i+'" alt="인덱스 업데이트" loading="lazy"></p><h2 id="내-노드에-들어오는-신청-처리" tabindex="-1">내 노드에 들어오는 신청 처리 <a class="header-anchor" href="#내-노드에-들어오는-신청-처리" aria-label="Permalink to &quot;내 노드에 들어오는 신청 처리&quot;">​</a></h2><p><code>내 노드 참여 신청</code> 탭에서는 다른 사람이 내 노드에 참여하려는 요청을 처리합니다.</p><p><img src="'+l+'" alt="참여 신청" loading="lazy"></p><p>초대 링크를 만들려면 로컬 노드를 켜고, <code>송신 인덱스 업데이트</code>를 한 번 실행해 외부 도메인을 확인한 뒤 <code>초대 링크 재설정</code>을 누릅니다.</p><p>신청이 들어오면 다음 작업을 할 수 있습니다.</p><table tabindex="0"><thead><tr><th>작업</th><th>의미</th></tr></thead><tbody><tr><td>승인</td><td>상대가 내 공유 파일 목록을 동기화하도록 허용</td></tr><tr><td>거절</td><td>참여를 허용하지 않음</td></tr><tr><td>삭제</td><td>종료된 기록 삭제</td></tr><tr><td>상태 확인</td><td>상대가 이 관계를 유지 중인지 확인</td></tr></tbody></table><p>승인한 뒤에도 상대 측에서 수신 인덱스를 업데이트해야 내 공유 파일이 보입니다.</p><p><img src="'+d+'" alt="노드 승인" loading="lazy"></p><h2 id="메시지" tabindex="-1">메시지 <a class="header-anchor" href="#메시지" aria-label="Permalink to &quot;메시지&quot;">​</a></h2><p>관계가 승인된 뒤에는 노드 카드에서 메시지를 보낼 수 있습니다.</p><p>메시지는 연합 관계에 대한 연락 용도일 뿐, 파일, 태그, 디렉터리, 권한에는 영향을 주지 않습니다.</p><p><img src="'+o+'" alt="메시지" loading="lazy"></p><h2 id="연합-파일-보기" tabindex="-1">연합 파일 보기 <a class="header-anchor" href="#연합-파일-보기" aria-label="Permalink to &quot;연합 파일 보기&quot;">​</a></h2><p>동기화가 끝나면 관리자 파일 목록으로 돌아갑니다. 화면 상단에서 로컬 파일과 연합 파일을 전환할 수 있습니다.</p><p>연합 파일은 외부 노드의 파일 목록입니다. 내 사이트의 로컬 파일이 아니므로 이동, 삭제, 태그 수정, 백업은 할 수 없습니다.</p><p><img src="'+r+'" alt="관리 화면 표시" loading="lazy"></p><h2 id="자주-확인할-점" tabindex="-1">자주 확인할 점 <a class="header-anchor" href="#자주-확인할-점" aria-label="Permalink to &quot;자주 확인할 점&quot;">​</a></h2><h3 id="관계-기록이-없다고-나오면" tabindex="-1">관계 기록이 없다고 나오면 <a class="header-anchor" href="#관계-기록이-없다고-나오면" aria-label="Permalink to &quot;관계 기록이 없다고 나오면&quot;">​</a></h3><p>상대가 내 기록을 삭제했을 가능성이 큽니다. 이 경우 다시 참여 신청을 해야 합니다.</p><p><img src="'+s+'" alt="재신청" loading="lazy"></p><h3 id="참여했는데-파일이-보이지-않으면" tabindex="-1">참여했는데 파일이 보이지 않으면 <a class="header-anchor" href="#참여했는데-파일이-보이지-않으면" aria-label="Permalink to &quot;참여했는데 파일이 보이지 않으면&quot;">​</a></h3><p>다음을 확인합니다.</p><ol><li>상대가 내 신청을 승인했는지.</li><li>상대가 송신 인덱스를 업데이트했는지.</li><li>내가 수신 인덱스를 업데이트했는지.</li><li>상대의 동기화 폴더에 공유하려는 디렉터리가 포함되어 있는지.</li></ol>',54)])])}const y=p(b,[["render",u]]);export{P as __pageData,y as default};
